package com.example.samlsp.web;

import jakarta.servlet.http.HttpServletRequest;
import org.springframework.http.MediaType;
import org.springframework.security.saml2.provider.service.metadata.Saml2MetadataResolver;
import org.springframework.security.saml2.provider.service.registration.RelyingPartyRegistration;
import org.springframework.security.saml2.provider.service.registration.RelyingPartyRegistrationRepository;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
public class SamlMetadataController {

    private final RelyingPartyRegistrationRepository relyingPartyRegistrationRepository;
    private final Saml2MetadataResolver metadataResolver;

    public SamlMetadataController(RelyingPartyRegistrationRepository relyingPartyRegistrationRepository,
                                  Saml2MetadataResolver metadataResolver) {
        this.relyingPartyRegistrationRepository = relyingPartyRegistrationRepository;
        this.metadataResolver = metadataResolver;
    }

    @GetMapping(value = "/saml/sp/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public String metadata(HttpServletRequest request) {
        RelyingPartyRegistration rp = relyingPartyRegistrationRepository.findByRegistrationId("cloud-sso");
        return metadataResolver.resolve(rp);
    }
}

package com.example.samlsp.web;

import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.saml2.provider.service.authentication.Saml2AuthenticatedPrincipal;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.LinkedHashMap;
import java.util.Map;

@RestController
public class MeController {

    @GetMapping("/me")
    public Map<String, Object> me(@AuthenticationPrincipal Saml2AuthenticatedPrincipal principal) {
        Map<String, Object> m = new LinkedHashMap<>();
        if (principal == null) {
            m.put("authenticated", false);
            return m;
        }
        m.put("authenticated", true);
        m.put("name", principal.getName());
        m.put("attributes", principal.getAttributes());
        m.put("sessionIndexes", principal.getSessionIndexes());
        return m;
    }

    @GetMapping("/")
    public Map<String, Object> home() {
        Map<String, Object> m = new LinkedHashMap<>();
        m.put("ok", true);
        m.put("endpoints", new String[]{"/saml/sp/metadata", "/saml2/authenticate/{registrationId}", "/logout", "/me"});
        return m;
    }
}

